# Kinetic Team Hybrid

Team member list with cursor-tracking floating image card on desktop and inline accordion image reveal on mobile. Each row dims when another is hovered, and the active member's photo follows the cursor with spring physics. Uses Framer Motion and Next.js Image.

## Use when
- Building a team or about page section with engaging hover interactions.
- Displaying an about page where team member photos reveal on hover.
- Establishing a serious, typographic brand personality with a kinetic list layout.

## Stack
- Framework: react
- Libraries: framer-motion, lucide-react, next
- Requires: tailwind

## Install
```bash
next, lucide-react, framer-motion
```

## Component — kinetic-team-hybrid.tsx
```tsx
'use client';
import React, { useState, useRef, useEffect } from 'react';
import {
  motion,
  useMotionValue,
  useSpring,
  AnimatePresence,
} from 'framer-motion';
import { ArrowUpRight, Minus, Plus } from 'lucide-react';
import Image from 'next/image';

interface TeamMember {
  id: string;
  name: string;
  role: string;
  image: string;
}

const TEAM: TeamMember[] = [
  {
    id: '01',
    name: 'Alex Morgan',
    role: 'Design Director',
    image: 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=1000&auto=format&fit=crop',
  },
  {
    id: '02',
    name: 'Jordan Lee',
    role: 'Lead Architect',
    image: 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=1000&auto=format&fit=crop',
  },
  {
    id: '03',
    name: 'Casey Smith',
    role: 'Creative Technologist',
    image: 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=1000&auto=format&fit=crop',
  },
  {
    id: '04',
    name: 'Taylor Reed',
    role: 'Brand Strategist',
    image: 'https://images.unsplash.com/photo-1531746020798-e6953c6e8e04?q=80&w=1000&auto=format&fit=crop',
  },
  {
    id: '05',
    name: 'Riley Davis',
    role: 'Motion Designer',
    image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=1000&auto=format&fit=crop',
  },
];

export default function KineticTeamHybrid() {
  const [activeId, setActiveId] = useState<string | null>(null);
  const [isMobile, setIsMobile] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);
  const springConfig = { damping: 20, stiffness: 150, mass: 0.5 };
  const cursorX = useSpring(mouseX, springConfig);
  const cursorY = useSpring(mouseY, springConfig);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 768);
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isMobile) return;
    mouseX.set(e.clientX + 20);
    mouseY.set(e.clientY + 20);
  };

  return (
    <div
      ref={containerRef}
      onMouseMove={handleMouseMove}
      className="relative min-h-screen w-full cursor-default bg-neutral-950 px-6 py-24 text-neutral-200 md:px-12"
    >
      {/* [Full component JSX — see source file for TeamRow sub-component and floating card] */}
    </div>
  );
}
```

## Demo
```tsx
import KineticTeamList from "@/components/ui/kinetic-team-hybrid";

export default function DemoOne() {
  return <KineticTeamList />;
}
```

## Notes
- Imports `Image` from `next/image` — requires Next.js. In non-Next projects, replace with a plain `<img>` tag.
- The floating cursor card uses `position: fixed` and `left-0 top-0` with CSS transform for positioning — ensure no parent has `transform` or `will-change` that creates a new stacking context.
